"""Git utilities for idempotent reference-doc generation (ADR-158 A-2).

Checks whether generated content differs from existing files before writing.
Prevents no-op commits and provides diff preview.
"""

from __future__ import annotations

import difflib
import logging
from dataclasses import dataclass
from datetime import datetime, timezone
from pathlib import Path

logger = logging.getLogger(__name__)

HEADER_TEMPLATE = (
    "<!-- AUTO-GENERATED by /session-docu — DO NOT EDIT MANUALLY -->\n"
    "<!-- Generated: {timestamp} | Version: {version} -->\n"
)


@dataclass
class WriteResult:
    path: Path
    changed: bool
    diff_lines: list[str]
    written: bool = False


def prepare_content(content: str, *, version: str = "1") -> str:
    """Prepend timestamp + version header to generated content."""
    timestamp = datetime.now(tz=timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
    header = HEADER_TEMPLATE.format(timestamp=timestamp, version=version)
    # Replace the first auto-generated comment if present
    if content.startswith("<!-- AUTO-GENERATED"):
        first_newline = content.index("\n")
        content = content[first_newline + 1:]
    return header + content


def check_diff(existing_path: Path, new_content: str) -> WriteResult:
    """Compare new content against existing file, ignoring timestamp lines."""
    if not existing_path.exists():
        return WriteResult(
            path=existing_path,
            changed=True,
            diff_lines=[f"+++ {existing_path} (new file)"],
        )

    existing = existing_path.read_text(encoding="utf-8")

    # Strip auto-generated header lines for comparison
    existing_body = _strip_header(existing)
    new_body = _strip_header(new_content)

    if existing_body == new_body:
        return WriteResult(path=existing_path, changed=False, diff_lines=[])

    diff = list(
        difflib.unified_diff(
            existing.splitlines(),
            new_content.splitlines(),
            fromfile=f"a/{existing_path.name}",
            tofile=f"b/{existing_path.name}",
            lineterm="",
        )
    )

    return WriteResult(path=existing_path, changed=True, diff_lines=diff)


def write_if_changed(
    target_path: Path,
    content: str,
    *,
    dry_run: bool = True,
    version: str = "1",
) -> WriteResult:
    """Write content to file only if it differs from existing (A-2 idempotency).

    Args:
        target_path: Where to write the generated doc.
        content: The generated Markdown content.
        dry_run: If True, don't write — just report diff.
        version: Version string for the header.
    """
    final_content = prepare_content(content, version=version)
    result = check_diff(target_path, final_content)

    if not result.changed:
        logger.info("No changes for %s — skipping.", target_path)
        return result

    if dry_run:
        logger.info("DRY RUN: Would write %s (%d diff lines)", target_path, len(result.diff_lines))
        return result

    target_path.parent.mkdir(parents=True, exist_ok=True)
    target_path.write_text(final_content, encoding="utf-8")
    result.written = True
    logger.info("Written %s", target_path)
    return result


def _strip_header(content: str) -> str:
    """Remove auto-generated header lines for content comparison."""
    lines = content.splitlines()
    body_lines = []
    for line in lines:
        if line.startswith("<!-- AUTO-GENERATED") or line.startswith("<!-- Generated"):
            continue
        body_lines.append(line)
    return "\n".join(body_lines)
